from flask import Flask, request
import json
import os
import time
import msgpack
from datetime import datetime, timedelta
import dateutil.parser

app = Flask(__name__)

CACHE_DIR = "./cache"
CACHE_EXPIRE_TIME = timedelta(hours=1)  # Cache expiry time 1 hour

if not os.path.isdir(CACHE_DIR):
    os.mkdir(CACHE_DIR)


def cache_filename(url):
    return os.path.join(CACHE_DIR, url.replace("/", "_") + ".cache")


def load_from_cache(url):
    filename = cache_filename(url)
    if not os.path.isfile(filename):
        return None

    with open(filename, "rb") as file:
        raw_data = file.read()

    data = msgpack.unpack(raw_data)

    timestamp = dateutil.parser.parse(data['timestamp'])

    if timestamp + CACHE_EXPIRE_TIME < datetime.now():
        remove_from_cache(url)
        return None

    return data['response']


def save_to_cache(url, data):
    timestamp = datetime.now().isoformat()
    data_to_cache = {
        "timestamp": timestamp,
        "response": data,
    }

    serialized_data = msgpack.pack(data_to_cache)

    with open(cache_filename(url), "wb") as file:
        file.write(serialized_data)


def remove_from_cache(url):
    filename = cache_filename(url)
    if os.path.isfile(filename):
        os.remove(filename)


@app.route('/api/<path:subpath>', methods=['GET'])
def fetch_from_api(subpath):
    url = request.path

    # Check for cached data
    data = load_from_cache(url)
    if data is not None:
        return json.dumps(data)

    # Expensive API request not shown here, for example:
    # result = requests.get(SOME_API_PATH + url).json()

    result = {"example": "This is an example response"}

    # Save the result to cache
    save_to_cache(url, result)

    return json.dumps(result)


if __name__ == "__main__":
    app.run(debug=True)